const v = $('Validate purchase').first().json;
const txnRef = ($('Log purchase').first().json.fields && $('Log purchase').first().json.fields.TxnRef) ? $('Log purchase').first().json.fields.TxnRef : ("OR-" + Date.now());
const out = (v.items || []).map(i => ({ json:{
  txnRef, item:i.name, category:i.category || "", qty:i.qty || 1, price:i.price || 0,
  cashier:v.by, accountId:v.accountId
} }));
return out.length ? out : [{ json:{ txnRef, item:null } }];

